mapper.select:
SELECT

FROM tb_member a
WHERE a.id = #{id}

SELECT

FROM tb_member a
WHERE a.login_name = #{loginName}

SELECT

FROM tb_member a
WHERE a.email = #{email}

SELECT

FROM tb_member a

    a.del_flag = #{DEL_FLAG_NORMAL}

        AND a.enable_flag = #{queryEnableFlag}


        AND a.email LIKE CONCAT('%', #{queryEmail}, '%')


        AND a.name LIKE CONCAT('%', #{queryName}, '%')


        AND a.remarks LIKE CONCAT('%', #{queryRemarks}, '%')


        AND a.register_date BETWEEN #{queryBeginRegisterDate} AND #{queryEndRegisterDate}


        AND a.last_login_date BETWEEN #{queryBeginLoginDate} AND #{queryEndLoginDate}


        and a.mobile = #{queryMobile}


ORDER BY a.priority, a.email

mapper.update:
UPDATE tb_member
SET last_login_ip   = #{lastLoginIp},
    last_login_date = #{lastLoginDate},
    login_count = #{loginCount}
WHERE id = #{id}

UPDATE tb_member
SET login_pass = #{loginPass}
WHERE id = #{id}

UPDATE tb_member
SET enable_flag = #{enableFlag},
    update_date = #{updateDate}
WHERE id = #{id}

UPDATE tb_member
SET priority    = #{priority},
    update_date = #{updateDate}
WHERE id = #{id}

